#include <iostream>\n#include <string>\n#include <algorithm>\n\nclass Notepad {\npublic:\n    // Convert text to uppercase\n    static std::string toUpperCase(const std::string& text) {\n        std::string result = text;\n        std::transform(result.begin(), result.end(), result.begin(), ::toupper);\n        return result;\n    }\n\n    // Convert text to lowercase\n    static std::string toLowerCase(const std::string& text) {\n        std::string result = text;\n        std::transform(result.begin(), result.end(), result.begin(), ::tolower);\n        return result;\n    }\n\n    // Trim whitespace from both ends of a string\n    static std::string trim(const std::string& text) {\n        size_t first = text.find_first_not_of(' ');\n        size_t last = text.find_last_not_of(' ');\n        return text.substr(first, (last - first + 1));\n    }\n\n    // Find and replace substrings\n    static std::string findAndReplace(std::string text, const std::string& toSearch, const std::string& toReplace) {\n        size_t pos = 0;\n        while ((pos = text.find(toSearch, pos)) != std::string::npos) {\n            text.replace(pos, toSearch.length(), toReplace);\n            pos += toReplace.length();\n        }\n        return text;\n    }\n\n    // Menu-driven interface\n    static void run() {\n        int choice;\n        std::string text, searchStr, replaceStr;\n\n        while (true) {\n            std::cout << "\n1. Convert to Uppercase\n2. Convert to Lowercase\n3. Trim Whitespace\n4. Find and Replace\n5. Exit\nChoose an option: ";\n            std::cin >> choice;\n            std::cin.ignore(); // ignore newline character\n\n            switch (choice) {\n                case 1:\n                    std::cout << "Enter text: ";\n                    std::getline(std::cin, text);\n                    std::cout << toUpperCase(text);\n                    break;\n                case 2:\n                    std::cout << "Enter text: ";\n                    std::getline(std::cin, text);\n                    std::cout << toLowerCase(text);\n                    break;\n                case 3:\n                    std::cout << "Enter text: ";\n                    std::getline(std::cin, text);\n                    std::cout << trim(text);\n                    break;\n                case 4:\n                    std::cout << "Enter text: ";\n                    std::getline(std::cin, text);\n                    std::cout << "Enter the substring to find: ";\n                    std::getline(std::cin, searchStr);\n                    std::cout << "Enter the substring to replace with: ";\n                    std::getline(std::cin, replaceStr);\n                    std::cout << findAndReplace(text, searchStr, replaceStr);\n                    break;\n                case 5:\n                    return;\n                default:\n                    std::cout << "Invalid choice, please try again.";\n            }\n        }\n    }\n};\n\nint main() {\n    Notepad::run();\n    return 0;\n}